<?php require_once __DIR__.'/../../config/database.php'; require_once __DIR__.'/../../includes/functions.php'; require_admin(); if($_SERVER['REQUEST_METHOD']==='POST'){ if(isset($_POST['delete']))$pdo->prepare('DELETE FROM symptoms WHERE id=?')->execute([$_POST['id']]); else $pdo->prepare('INSERT INTO symptoms(variable_id,code,name,category,description,reference_id) VALUES(?,?,?,?,?,1)')->execute([$_POST['variable_id'],$_POST['code'],$_POST['name'],$_POST['category'],$_POST['description']]); } $vars=$pdo->query('SELECT * FROM variables')->fetchAll(); $rows=$pdo->query('SELECT s.*,v.code vcode FROM symptoms s JOIN variables v ON v.id=s.variable_id ORDER BY s.id')->fetchAll(); require_once __DIR__.'/../../includes/header.php'; ?><div class="container"><h2>Master Knowledge Base</h2><form class="card p-3 mb-3" method="post"><div class="row g-2"><div class="col"><select name="variable_id" class="form-select"><?php foreach($vars as $v): ?><option value="<?=$v['id']?>"><?=$v['code']?></option><?php endforeach; ?></select></div><div class="col"><input name="code" class="form-control" placeholder="Kode"></div><div class="col"><input name="name" class="form-control" placeholder="Nama"></div><div class="col"><input name="category" class="form-control" placeholder="Kategori"></div><div class="col"><input name="description" class="form-control" placeholder="Keterangan"></div><div class="col"><button class="btn btn-primary">Simpan</button></div></div></form><table class="table"><tr><th>Kode</th><th>Variabel</th><th>Nama</th><th>Kategori</th><th>Keterangan</th><th>Referensi</th><th>Aksi</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['code'])?></td><td><?=e($r['vcode'])?></td><td><?=e($r['name'])?></td><td><?=e($r['category'])?></td><td><?=e($r['description'])?></td><td>Laporan Akademik</td><td><form method="post"><input type="hidden" name="id" value="<?=$r['id']?>"><button name="delete" class="btn btn-sm btn-danger">Hapus</button></form></td></tr><?php endforeach; ?></table></div><?php require_once __DIR__.'/../../includes/footer.php'; ?>
